sql:
SELECT template_name
FROM templates
WHERE status = 'Approved';

SELECT template_name, last_modified_date, average_rating
FROM templates
ORDER BY last_modified_date DESC;

external_knowledge:
- 'Reputation' refers to the overall standing of a template, which is based on its average rating, number of comments, and number of collaborators; 
- 'Fame' is indicated by the number of collaborators for a template; 
- 'Popularity' is measured by the number of comments a template has received; 
- 'Prestige' is synonymous with the average rating of a template.

sql:
SELECT template_name, template_id
FROM templates
ORDER BY template_name;

SELECT created_by, COUNT(*) AS template_count
FROM templates
GROUP BY created_by;

SELECT template_name, version
FROM templates
ORDER BY created_date, template_name;

SELECT template_name, last_modified_date
FROM templates
ORDER BY last_modified_date DESC, template_name ASC;

SELECT COUNT(template_id) AS approved_templates_count
FROM template_approvals
WHERE approval_status = 'Approved';

SELECT template_name, average_rating
FROM templates
ORDER BY average_rating DESC;
